mapper.select:
SELECT p.participant_seq ,p.email ,TRIM(CONCAT_WS(' ', p.first_name, NULLIF(p.middle_name, ''), p.last_name)) AS full_name ,p.organization_name ,p.position ,p.country ,p.phone ,p.address ,p.city ,p.nationality ,COALESCE(p.residence_country, p.country) AS residence_country ,COALESCE(pc.total_event_count, 0) AS total_event_count ,ep.event_participant_seq ,ep.event_seq ,e.title AS event_title ,e.event_type ,ep.participant_type_cd ,COALESCE(ptc.com_cd_nm, ep.participant_type_cd) AS participant_type_name ,COALESCE(NULLIF(pay.price_name, ''), NULLIF(pay.price_type, '')) AS payment_name ,pay.payment_seq ,pay.status AS payment_status ,pay.amount AS payment_amount ,pay.currency AS payment_currency ,pay.payment_method ,pay.pg_order_id AS payment_order_id ,pay.pg_transaction_id AS payment_transaction_id ,pay.refunded_amount AS payment_refunded_amount ,pay.paid_at AS payment_paid_at ,pay.cancelled_at AS payment_cancelled_at ,ep.status AS participation_status ,ep.registered_at ,ep.cancelled_at ,ep.cancel_reason ,MAX(ep.registered_at) OVER (PARTITION BY p.participant_seq) AS participant_latest_registered_at FROM event.participants p INNER JOIN event.event_participants ep ON ep.participant_seq = p.participant_seq INNER JOIN event.events e ON e.event_seq = ep.event_seq AND e.deleted_at IS NULL LEFT JOIN event.com_grp_cd ptg ON ptg.com_grp_cd = 'PARTICIPANT_TYPE' AND ptg.use_yn = 'Y' LEFT JOIN event.com_cd ptc ON ptc.com_grp_cd_seq = ptg.com_grp_cd_seq AND ptc.com_cd = ep.participant_type_cd AND ptc.use_yn = 'Y' LEFT JOIN LATERAL ( SELECT pr.price_name ,pr.price_type ,pmt.payment_seq ,pmt.status ,pmt.amount ,pmt.currency ,pmt.payment_method ,pmt.pg_order_id ,pmt.pg_transaction_id ,pmt.refunded_amount ,pmt.paid_at ,pmt.cancelled_at FROM event.payments pmt LEFT JOIN event.event_pricing pr ON pr.event_pricing_seq = pmt.event_pricing_seq AND pr.deleted_at IS NULL WHERE ( pmt.event_participant_seq = ep.event_participant_seq OR ( pmt.event_participant_seq IS NULL AND pmt.event_seq = ep.event_seq AND pmt.participant_seq = p.participant_seq ) ) ORDER BY CASE pmt.status WHEN 'paid' THEN 1 WHEN 'cancelled' THEN 2 WHEN 'failed' THEN 4 ELSE 3 END ,COALESCE(pmt.paid_at, pmt.created_at) DESC NULLS LAST ,pmt.payment_seq DESC LIMIT 1 ) pay ON TRUE LEFT JOIN ( SELECT ep2.participant_seq ,COUNT(*) AS total_event_count FROM event.event_participants ep2 INNER JOIN event.events e2 ON e2.event_seq = ep2.event_seq AND e2.deleted_at IS NULL WHERE 1 = 1
AND e2.organization_seq = #{organizationSeq}
GROUP BY ep2.participant_seq ) pc ON pc.participant_seq = p.participant_seq
AND e.organization_seq = #{organizationSeq}
AND ( LOWER(TRIM(CONCAT_WS(' ', p.first_name, NULLIF(p.middle_name, ''), p.last_name))) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(p.email) LIKE '%' || LOWER(#{keyword}) || '%' )
AND e.event_seq IN
#{eventSeq}
AND ep.status IN
#{status}
ORDER BY participant_latest_registered_at DESC NULLS LAST ,p.participant_seq DESC ,ep.registered_at DESC NULLS LAST ,ep.event_participant_seq DESC

SELECT e.event_seq ,e.title ,e.event_type ,e.start_at FROM event.events e WHERE e.deleted_at IS NULL
AND e.organization_seq = #{organizationSeq}
ORDER BY e.start_at DESC NULLS LAST, e.event_seq DESC

mapper.update:
UPDATE event.event_participants ep
SET participant_type_cd = NULLIF(#{participantTypeCd,jdbcType=VARCHAR}, '')
FROM event.events e
WHERE ep.event_seq = e.event_seq
  AND e.deleted_at IS NULL
  AND ep.participant_seq = #{participantSeq}
  AND ep.event_participant_seq = #{eventParticipantSeq}

  AND e.organization_seq = #{organizationSeq}
